-- Program: Joint-Friendly Full Body
-- Category: Body-Specific -> body_specific
-- Priority: high
-- Durations: [4, 8, 12], Sessions: [3, 4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Joint-Friendly Full Body',
    'Full body strength program designed for individuals with arthritis, joint sensitivity, or past injuries. Uses joint-safe exercises with reduced range of motion where needed, machine-assisted movements, and dedicated mobility work.',
    'body_specific',
    'all_levels',
    12,
    4,
    'full_body',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Improve flexibility', 'Enhance body awareness']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Joint-Friendly Full Body - 4w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Joint-Friendly Full Body - 4w 3x/wk',
    'body_specific',
    3,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Joint-Friendly Full Body'
ON CONFLICT DO NOTHING;

