    'Joint-Friendly Full Body',
    'Joint-Friendly Full Body - 12w 3x/wk',
    'high',
    false,
    'Full body strength program designed for individuals with arthritis, joint sensitivity, or past injuries. Uses joint-safe exercises with reduced range of motion where needed, machine-assisted movements, and dedicated mobility work.',
    'Body-Specific'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Joint-Friendly Full Body'
  AND pv.duration_weeks = 12
  AND pv.sessions_per_week = 3
ON CONFLICT DO NOTHING;

